import { clone } from 'lodash-es';
import { Children, Fragment, type JSX, type ReactNode } from 'react';

import { isSlot } from '../../../../../core/utils/is-slot.js';
import type { TruncationMode } from '../../../../../typography/text-ellipsis/TextEllipsis.js';
import { Footer } from '../components/Footer.js';
import { Action } from '../components/global-actions/Action.js';
import { ActionsPlaceholder } from '../components/global-actions/ActionsPlaceholder.js';
import { Header } from '../components/header/Header.js';
import { Series } from '../components/series/Series.js';
import { SeriesHeader } from '../components/series/SeriesHeader.js';
import { SeriesItem } from '../components/series/SeriesItem.js';
import { DEFAULT_TRUNCATION_MODE } from '../constants.js';
import type { DefaultConfigByGeometry, ExternalConfig } from '../types.js';

const VALID_TRUNCATION_MODES: TruncationMode[] = ['start', 'middle', 'end'];

const isValidTruncationMode = (value: unknown): value is TruncationMode => {
  return (
    typeof value === 'string' &&
    VALID_TRUNCATION_MODES.includes(value as TruncationMode)
  );
};

const getTruncationMode = (
  userTruncationMode: TruncationMode,
  defaultConfigTruncationMode?: TruncationMode,
): TruncationMode => {
  if (isValidTruncationMode(userTruncationMode)) {
    return userTruncationMode;
  }

  if (isValidTruncationMode(defaultConfigTruncationMode)) {
    return defaultConfigTruncationMode;
  }

  return DEFAULT_TRUNCATION_MODE;
};

export function buildContent(
  children: ReactNode,
  defaultConfig: null | DefaultConfigByGeometry[keyof DefaultConfigByGeometry],
  args: {
    userSymbolPosition: ExternalConfig['symbolPosition'];
    userTruncationMode: ExternalConfig['truncationMode'];
    customTooltip: boolean;
  },
): {
  content: ReactNode;
  config: ExternalConfig;
} {
  const slots: {
    Header: JSX.Element | null;
    Footer: JSX.Element | null;
    Series: JSX.Element | null;
    SeriesItem: JSX.Element | null;
    SeriesHeader: JSX.Element | null;
    ActionsPlaceholder: JSX.Element | null;
    GlobalActions: ReactNode[];
  } = {
    Header: null,
    Footer: null,
    Series: null,
    SeriesHeader: null,
    SeriesItem: null,
    ActionsPlaceholder: null,
    GlobalActions: [],
  };
  let unpinnedPlaceholderText: string | undefined;
  let defaultActionsConfig =
    defaultConfig?.defaultActionsConfig as ExternalConfig['defaultActionsConfig'];

  if (!args.customTooltip) {
    Children.forEach(children, (child) => {
      if (isSlot(child, Header)) {
        slots.Header = child;
      } else if (isSlot(child, Footer)) {
          slots.Footer = child;
      } else if (isSlot(child, SeriesHeader)) {
        slots.SeriesHeader = child;
        defaultActionsConfig = clone(
          defaultConfig?.defaultActionsConfig,
        ) as ExternalConfig['defaultActionsConfig'];
        const defaultNameAction = defaultActionsConfig?.get('name');
        if (child.props.seriesLabel && defaultNameAction) {
          defaultActionsConfig?.set('name', {
            ...defaultNameAction,
            customLabel: child.props.seriesLabel,
          });
        }

        const defaultValueAction = defaultActionsConfig?.get('value');
        if (child.props.valueLabel && defaultValueAction) {
          defaultActionsConfig?.set('value', {
            ...defaultValueAction,
            customLabel: child.props.valueLabel,
          });
        }
      } else if (isSlot(child, Series)) {
        slots.Series = child;
      } else if (isSlot(child, SeriesItem)) {
        slots.SeriesItem = child;
      } else if (isSlot(child, ActionsPlaceholder)) {
        unpinnedPlaceholderText = child.props.text;
      } else if (isSlot(child, Action)) {
        slots.GlobalActions.push(child);
      }
    });
  }

  return {
    content: [
      <Fragment key="header">{slots.Header}</Fragment>,
      slots.SeriesItem ? (
        <Fragment key="seriesHeader">
          {slots.SeriesHeader || <SeriesHeader />}
        </Fragment>
      ) : null,
      <Fragment key="series">{slots.Series || slots.SeriesItem}</Fragment>,
      slots.Footer ?? (
        <Footer
          key="footer"
          actions={slots.GlobalActions}
          unpinnedPlaceholderText={unpinnedPlaceholderText}
        />
      ),
    ],
    config: {
      seriesHeader: slots.SeriesHeader || <SeriesHeader />,
      displayHeaderDivider: !!(
        slots.Header &&
        (slots.Series || slots.SeriesItem)
      ),
      symbolPosition:
        args.userSymbolPosition || defaultConfig?.symbolPosition || 'left',
      truncationMode: getTruncationMode(
        args.userTruncationMode,
        defaultConfig?.truncationMode,
      ),
      defaultActionsConfig,
      variant:
        args.customTooltip ||
        (defaultConfig?.sharedVariant &&
          slots.Series?.props.variant === 'shared')
          ? 'shared'
          : 'single',
    },
  };
}
